7	#include <boost/algorithm/string.hpp>
8	#include <boost/range/adaptor/reversed.hpp>
9	#include <rime/candidate.h>
10	#include <rime/composition.h>
11	#include <rime/menu.h>
12	
13	namespace rime {
14	
15	bool Composition::HasFinishedComposition() const {
16	  if (empty())
17	    return false;
18	  size_t k = size() - 1;
19	  if (k > 0 && at(k).start == at(k).end)
20	    --k;
21	  return at(k).status >= Segment::kSelected;
22	}
23	
24	Preedit Composition::GetPreedit(const string& full_input,
25	                                size_t caret_pos,
26	                                const string& caret) const {
27	  Preedit preedit;
28	  preedit.caret_pos = string::npos;
29	  size_t start = 0;
30	  size_t end = 0;
31	  for (size_t i = 0; i < size(); ++i) {
32	    start = end;
33	    if (caret_pos == start) {
34	      preedit.caret_pos = preedit.text.length();
35	    }
36	    auto cand = at(i).GetSelectedCandidate();
37	    if (i < size() - 1) {  // converted
38	      if (cand) {
39	        end = cand->end();
40	        preedit.text += cand->text();
41	      } else {  // raw input
42	        end = at(i).end;
43	        if (!at(i).HasTag("phony")) {
44	          preedit.text += input_.substr(start, end - start);
45	        }
46	      }
47	    } else {  // highlighted
48	      preedit.sel_start = preedit.text.length();
49	      preedit.sel_end = string::npos;
50	      if (cand && !cand->preedit().empty()) {
51	        end = cand->end();
52	        auto caret_placeholder = cand->preedit().find('\t');
53	        if (caret_placeholder != string::npos) {
54	          preedit.text += cand->preedit().substr(0, caret_placeholder);
55	          // the part after caret is considered prompt string,
56	          // show it only when the caret is at the end of input.
57	          if (caret_pos == end && end == full_input.length()) {
