9	#include <ostream>
10	#include <rime/menu.h>
11	#include <rime/segmentation.h>
12	
13	namespace rime {
14	
15	static const char* kPartialSelectionTag = "partial";
16	
17	void Segment::Close() {
18	  auto cand = GetSelectedCandidate();
19	  if (cand && cand->end() < end) {
20	    // having selected a partially matched candidate, split it into 2 segments
21	    end = cand->end();
22	    tags.insert(kPartialSelectionTag);
23	  }
24	}
25	
26	bool Segment::Reopen(size_t caret_pos) {
27	  if (status < kSelected) {
28	    return false;
29	  }
30	  const size_t original_end_pos = start + length;
31	  if (original_end_pos == caret_pos) {
32	    // reuse previous candidates and keep selection
33	    if (end < original_end_pos) {
34	      // restore partial-selected segment
35	      end = original_end_pos;
36	      tags.erase(kPartialSelectionTag);
37	    }
38	    status = kGuess;
39	  } else {
40	    status = kVoid;
41	  }
42	  return true;
43	}
44	
45	an<Candidate> Segment::GetCandidateAt(size_t index) const {
46	  if (!menu)
47	    return nullptr;
48	  return menu->GetCandidateAt(index);
49	}
50	
51	an<Candidate> Segment::GetSelectedCandidate() const {
52	  return GetCandidateAt(selected_index);
53	}
54	
55	Segmentation::Segmentation() {}
56	
57	void Segmentation::Reset(const string& new_input) {
58	  DLOG(INFO) << "reset to " << size() << " segments.";
59	  // mark redo segmentation, while keeping user confirmed segments
60	  size_t diff_pos = 0;
61	  while (diff_pos < input_.length() && diff_pos < new_input.length() &&
62	         input_[diff_pos] == new_input[diff_pos])
63	    ++diff_pos;
64	  DLOG(INFO) << "diff pos: " << diff_pos;
65	
66	  // dispose segments that have changed
67	  int disposed = 0;
68	  while (!empty() && back().end > diff_pos) {
69	    pop_back();
70	    ++disposed;
71	  }
72	  if (disposed > 0)
73	    Forward();
74	
75	  input_ = new_input;
76	}
77	
78	void Segmentation::Reset(size_t num_segments) {
79	  if (num_segments >= size())
80	    return;
81	  resize(num_segments);
82	}
83	
84	bool Segmentation::AddSegment(Segment segment) {
85	  int start = GetCurrentStartPosition();
86	  if (segment.start != start) {
87	    // rule one: in one round, we examine only those segs
88	    // that are left-aligned to a same position
89	    return false;
90	  }
91	
92	  if (empty()) {
93	    push_back(segment);
94	    return true;
95	  }
96	
97	  Segment& last = back();
98	  if (last.end > segment.end) {
99	    // rule two: always prefer the longer segment...
100	  } else if (last.end < segment.end) {
101	    // ...and overwrite the shorter one
102	    last = segment;
103	  } else {
104	    // rule three: with segments equal in length, merge their tags
105	    set<string> result;
106	    set_union(last.tags.begin(), last.tags.end(), segment.tags.begin(),
107	              segment.tags.end(), std::inserter(result, result.begin()));
108	    last.tags.swap(result);
109	  }
110	  return true;
111	}
112	
113	// finalize a round
114	bool Segmentation::Forward() {
115	  if (empty() || back().start == back().end)
116	    return false;
117	  // initialize an empty segment for the next round
118	  push_back(Segment(back().end, back().end));
119	  return true;
120	}
121	
122	// remove empty trailing segment
123	bool Segmentation::Trim() {
124	  if (!empty() && back().start == back().end) {
125	    pop_back();
126	    return true;
127	  }
128	  return false;
129	}
130	
131	bool Segmentation::HasFinishedSegmentation() const {
132	  return (empty() ? 0 : back().end) >= input_.length();
133	}
134	
135	size_t Segmentation::GetCurrentStartPosition() const {
136	  return empty() ? 0 : back().start;
137	}
138	
139	size_t Segmentation::GetCurrentEndPosition() const {
140	  return empty() ? 0 : back().end;
141	}
142	
143	size_t Segmentation::GetCurrentSegmentLength() const {
144	  return empty() ? 0 : (back().end - back().start);
145	}
146	
147	size_t Segmentation::GetConfirmedPosition() const {
148	  size_t k = 0;
149	  for (const Segment& seg : *this) {
150	    if (seg.status >= Segment::kSelected)
151	      k = seg.end;
152	  }
153	  return k;
154	}
155	
156	std::ostream& operator<<(std::ostream& out, const Segmentation& segmentation) {
157	  out << "[" << segmentation.input();
158	  for (const Segment& segment : segmentation) {
159	    out << "|" << segment.start << "," << segment.end;
160	    if (!segment.tags.empty()) {
